interface ModelItemProps {
  model: Model
  selectedModel: string
  onSelect: (id: string) => void
}

const ModelItem = memo(({ model, selectedModel, onSelect }: ModelItemProps) => {
  const handleSelect = useCallback(
    () => onSelect(model.id),
    [onSelect, model.id]
  )

  return (
    <ModelSelectorItem onSelect={handleSelect} value={model.id}>
      <ModelSelectorLogo provider={model.chefSlug} />
      <ModelSelectorName>{model.name}</ModelSelectorName>
      <ModelSelectorLogoGroup>
        {model.providers.map((provider) => (
          <ModelSelectorLogo key={provider} provider={provider} />
        ))}
      </ModelSelectorLogoGroup>
      {selectedModel === model.id ? (
        <CheckIcon className="ml-auto size-4" />
      ) : (
        <div className="ml-auto size-4" />
      )}
    </ModelSelectorItem>
  )
})

ModelItem.displayName = "ModelItem"

export function ModelSelector({
  models = DEFAULT_MODELS,
  defaultModelId,
  onModelChange,
  className,
}: {
  models?: Model[]
  defaultModelId?: string
  onModelChange?: (model: Model) => void
  className?: string
}) {
  const [open, setOpen] = useState(false)
  const [selectedModel, setSelectedModel] = useState(
    defaultModelId ?? models[0]?.id ?? "gpt-4o"
  )

  const handleModelSelect = useCallback(
    (id: string) => {
      setSelectedModel(id)
      setOpen(false)
      const model = models.find((m) => m.id === id)
      if (model) onModelChange?.(model)
    },
    [models, onModelChange]
  )

  const selectedModelData = models.find((model) => model.id === selectedModel)

  const chefs = useMemo(
    () => [...new Set(models.map((model) => model.chef))],
    [models]
  )

  return (
    <ModelSelectorRoot onOpenChange={setOpen} open={open}>
      <ModelSelectorTrigger asChild>
        <Button
          className={cn("w-[200px] justify-between", className)}
          variant="outline"
        >
          {selectedModelData?.chefSlug && (
            <ModelSelectorLogo provider={selectedModelData.chefSlug} />
          )}
          {selectedModelData?.name && (
            <ModelSelectorName>{selectedModelData.name}</ModelSelectorName>
          )}
        </Button>
      </ModelSelectorTrigger>
      <ModelSelectorContent>
        <ModelSelectorInput placeholder="Search models..." />
        <ModelSelectorList>
          <ModelSelectorEmpty>No models found.</ModelSelectorEmpty>
          {chefs.map((chef) => (
            <ModelSelectorGroup heading={chef} key={chef}>
              {models
                .filter((model) => model.chef === chef)
                .map((model) => (
                  <ModelItem
                    key={model.id}
                    model={model}
                    onSelect={handleModelSelect}
                    selectedModel={selectedModel}
                  />
                ))}
            </ModelSelectorGroup>
          ))}
        </ModelSelectorList>
      </ModelSelectorContent>
    </ModelSelectorRoot>
  )
}
